--
-- Table structure for table `email_campaigns`
--

DROP TABLE IF EXISTS `email_campaigns`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `email_campaigns` (
  `id` int NOT NULL AUTO_INCREMENT,
  `created_by_user_id` int DEFAULT NULL,
  `subject` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `body` mediumtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `include_login_details` tinyint(1) NOT NULL DEFAULT '0',
  `department_filter` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `recipient_count` int NOT NULL DEFAULT '0',
  `attachments_json` mediumtext COLLATE utf8mb4_unicode_ci,
  `user_delivery_mode` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'smtp',
  `sender_email` varchar(190) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `manager_email` varchar(190) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `manager_report_sent` tinyint(1) NOT NULL DEFAULT '0',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_email_campaigns_created` (`created_at`),
  KEY `fk_email_campaigns_user` (`created_by_user_id`),
  CONSTRAINT `fk_email_campaigns_user` FOREIGN KEY (`created_by_user_id`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=14 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

