INSERT INTO `email_campaigns` VALUES (1,1,'מונדיאל 2026 - ניחושיח','צוות יקר,\r\n\r\nלקראת משחקי פיפא 2026 , פתחנו עבורכם את אתר הניחושיח הרשמי של החברה!\r\n\r\nלכניסה לאתר, כל אחד יקבל מייל אישי עם יוזר וסיסמה. \r\n\r\n אתר הניחושים של מונדיאל 2026\r\n\r\nחשוב לדעת:\r\n✅ יש להירשם ולהזין את הניחושים לפני תחילת המשחקים הרלוונטיים.\r\n✅ ניתן לעדכן עד שעה לפני בעיטת הפתיחה.\r\n✅ הניקוד יצטבר לאורך כל הטורניר בהתאם לתוצאות בפועל.\r\n✅ דירוג המשתתפים יתעדכן באופן שוטף באתר.\r\n✅ באתר ניתן להתעדכן בחדשות און ליין, הבתים ושעות המשחקים, בתקנון, מדיניות השתתפות ושיטת הניקוד. \r\n\r\nפרסים:\r\n🥉 במהלך הניחושיח יחולקו פרסים בהתאם לתוצאות.\r\nבגמר המונדיאל, יחולקו פרסים לשלושת המקומות הראשונים מובילי הטבלה. \r\n\r\nמומלץ להיכנס כבר עכשיו, להשלים את הניחושים ולהתחיל לטפס בטבלה!\r\nבהצלחה לכולם, וצפייה מהנה ⚽🌍🏆',1,NULL,2,'[]','smtp','mon2026@reports.seach.co.il','aviva@seach.co.il',1,'2026-06-10 12:48:46'),(2,1,'ניסוי שליחה','אימייל לבדיקה\r\nברכות',1,NULL,2,'[{\"filename\":\"â××× ×××× ×××¨××§ ×× ×¤×© ××××_ ×× ××¦××××¨ ×××¨×× ×¦×¨×× ×××¢×ª ×¢× ×§× ××××¡ ×¨×¤×××â (1).pdf\",\"size\":154601,\"mimeType\":\"application/pdf\"}]','smtp','mon2026@reports.seach.co.il','aviva@seach.co.il',1,'2026-06-10 12:52:56'),(3,1,'אתר הניחושיח - פיפא 2026','צוות יקר,\r\n\r\nלקראת משחקי פיפא 2026 , פתחנו עבורכם את אתר הניחושיח הרשמי של החברה!\r\n\r\nלכניסה לאתר, כל אחד יקבל מייל אישי עם יוזר וסיסמה. \r\n\r\n אתר הניחושים של מונדיאל 2026\r\n\r\nחשוב לדעת:\r\n✅ יש להירשם ולהזין את הניחושים לפני תחילת המשחקים הרלוונטיים.\r\n✅ ניתן לעדכן עד שעה לפני בעיטת הפתיחה.\r\n✅ הניקוד יצטבר לאורך כל הטורניר בהתאם לתוצאות בפועל.\r\n✅ דירוג המשתתפים יתעדכן באופן שוטף באתר.\r\n✅ באתר ניתן להתעדכן בחדשות און ליין, הבתים ושעות המשחקים, בתקנון, מדיניות השתתפות ושיטת הניקוד. \r\n\r\nפרסים:\r\n🥉 במהלך הניחושיח יחולקו פרסים בהתאם לתוצאות.\r\nבגמר המונדיאל, יחולקו פרסים לשלושת המקומות הראשונים מובילי הטבלה. \r\n\r\nמומלץ להיכנס כבר עכשיו, להשלים את הניחושים ולהתחיל לטפס בטבלה!\r\nבהצלחה לכולם, וצפייה מהנה ⚽🌍🏆',1,NULL,1,'[]','smtp','mon2026@reports.seach.co.il','aviva@seach.co.il',1,'2026-06-10 14:39:52'),(4,1,'קעלךי\'רףךלעין','געKJEדרףעןםיק,יםפ ח',1,NULL,1,'[]','smtp','mon2026@reports.seach.co.il','aviva@seach.co.il',1,'2026-06-10 14:44:01'),(5,1,'כלךר\'מעףםך\'ר','לךיכעףךר\'ינע',1,NULL,1,'[]','smtp','mon2026@reports.seach.co.il','aviva@seach.co.il',1,'2026-06-10 14:44:21'),(6,1,'ניסוי שליחה GAMIL','אנא התקשרו אם קיבלתן',1,NULL,3,'[]','smtp','mon2026@reports.seach.co.il','aviva@seach.co.il',1,'2026-06-10 15:42:38'),(7,1,'ssss','ssss',1,NULL,1,'[]','smtp','mon2026@reports.seach.co.il','aviva@seach.co.il',1,'2026-06-10 15:45:21'),(8,1,'ניסוי שליחה GMAILני','אנא השיבוי בוואטסאפ שקיבלתן',1,NULL,3,'[]','gmail','seachmessagecenter@gmail.com','aviva@seach.co.il',1,'2026-06-10 17:59:24'),(9,1,'ניסוי שליחה GMAILני','אנא השיבוי בוואטסאפ שקיבלתן',1,NULL,3,'[]','gmail','seachmessagecenter@gmail.com','aviva@seach.co.il',1,'2026-06-10 17:59:25'),(10,1,'פיפא 2026 יוצא לדרך – אתר הניחושים של שיח! ⚽🏆','צוות יקר,\r\n\r\nלקראת משחקי פיפא 2026 , פתחנו עבורכם את אתר הניחושיח הרשמי של החברה!\r\n\r\nלכניסה לאתר, כל אחד יקבל מייל אישי עם יוזר וסיסמה. \r\n\r\n אתר הניחושים של מונדיאל 2026\r\n\r\nחשוב לדעת:\r\n✅ יש להירשם ולהזין את הניחושים לפני תחילת המשחקים הרלוונטיים.\r\n✅ ניתן לעדכן עד שעה לפני בעיטת הפתיחה.\r\n✅ הניקוד יצטבר לאורך כל הטורניר בהתאם לתוצאות בפועל.\r\n✅ דירוג המשתתפים יתעדכן באופן שוטף באתר.\r\n✅ באתר ניתן להתעדכן בחדשות און ליין, הבתים ושעות המשחקים, בתקנון, מדיניות השתתפות ושיטת הניקוד. \r\n\r\nפרסים:\r\n🥉 במהלך הניחושיח יחולקו פרסים בהתאם לתוצאות.\r\nבגמר המונדיאל, יחולקו פרסים לשלושת המקומות הראשונים מובילי הטבלה. \r\n\r\nמומלץ להיכנס כבר עכשיו, להשלים את הניחושים ולהתחיל לטפס בטבלה!\r\nבהצלחה לכולם, וצפייה מהנה ⚽🌍🏆',1,NULL,2,'[]','gmail','seachmessagecenter@gmail.com','aviva@seach.co.il',1,'2026-06-10 18:26:18'),(11,1,'פיפא 2026 יוצא לדרך – אתר הניחושים של שיח! ⚽🏆','צוות יקר,\r\n\r\nלקראת משחקי פיפא 2026 , פתחנו עבורכם את אתר הניחושיח הרשמי של החברה