--
-- Table structure for table `players`
--

DROP TABLE IF EXISTS `players`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `players` (
  `id` int NOT NULL AUTO_INCREMENT,
  `external_id` int DEFAULT NULL,
  `name_en` varchar(160) COLLATE utf8mb4_unicode_ci NOT NULL,
  `name_he` varchar(160) COLLATE utf8mb4_unicode_ci NOT NULL,
  `country_en` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `country_he` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `team_code` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `image_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `external_id` (`external_id`),
  KEY `idx_players_name_en` (`name_en`),
  KEY `idx_players_country_en` (`country_en`),
  KEY `fk_players_team` (`team_code`),
  CONSTRAINT `fk_players_team` FOREIGN KEY (`team_code`) REFERENCES `teams` (`code`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=9451 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

