DROP TABLE IF EXISTS `schedule_items`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `schedule_items` (
  `id` int NOT NULL AUTO_INCREMENT,
  `title` varchar(160) COLLATE utf8mb4_unicode_ci NOT NULL,
  `date_label` varchar(120) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `start_at` datetime NOT NULL,
  `end_at` datetime NOT NULL,
  `sort_order` int NOT NULL DEFAULT '0',
  `prize_slot` tinyint DEFAULT NULL,
  `prize_image_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `winner_user_id` int DEFAULT NULL,
  `popup_enabled` tinyint(1) NOT NULL DEFAULT '0',
  `popup_title` varchar(160) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `popup_image_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `title` (`title`),
  KEY `idx_schedule_sort` (`sort_order`,`start_at`),
  KEY `idx_schedule_prize` (`prize_slot`),
  KEY `fk_schedule_winner` (`winner_user_id`),
  CONSTRAINT `fk_schedule_winner` FOREIGN KEY (`winner_user_id`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=741 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

